import React, { useEffect, useState } from "react";
import { createClient } from "@supabase/supabase-js";
import "./App.css";

// Supabase bağlantısı
const supabaseUrl = "https://cnakyamdydqxistdavfg.supabase.co";
const supabaseKey = "eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9...";
const supabase = createClient(supabaseUrl, supabaseKey);

// Kolonlar
const columnOrder = [
    "PROJE ADI", "TALEP", "TEDARİK", "VERİLEMEYEN", "TED. %",
    "SPOT", "FİLO", "TESİSTE", "GELECEK", "YÜKLENDİ",
    "HEDEF ÜSTÜ SEFER", "HEDEF ALTI SEFER", "HEDEF SEFER", "HEDEFSİZ SEFER"
];

// Proje adlarını normalize et
function normalizeProjectName(name) {
    if (name.startsWith("BUNGE ")) return "BUNGE LÜLEBURGAZ FTL";
    return name;
}

function App() {
    const [data, setData] = useState([]);
    const [odakData, setOdakData] = useState([]);
    const [mergedData, setMergedData] = useState([]);

    useEffect(() => {
        async function fetchSupabaseData() {
            const { data, error } = await supabase
                .from("toplu_sonuclar")
                .select("json_data")
                .order("created_at", { ascending: false })
                .limit(1)
                .single();

            if (error) {
                console.error("Supabase veri çekme hatası:", error);
                return;
            }

            if (data && data.json_data) {
                setData(data.json_data);
            }
        }

        fetchSupabaseData();
    }, []);

    useEffect(() => {
        async function fetchOdakData() {
            const today = new Date().toISOString().split("T")[0];
            const payload = {
                startDate: `${today}T00:00:00`,
                endDate: `${today}T23:59:59`,
                userId: 1,
            };

            try {
                const response = await fetch("/api/tmsorders/getall", {
                    method: "POST",
                    headers: {
                        "Content-Type": "application/json",
                        Authorization: "Bearer 49223653afa4b7e22c3659762c835dcdef9725a401e928fd46f697be8ea2597273bf4479cf9d0f7e5b8b03907c2a0b4d58625692c3e30629ac01fc477774de75",
                    },
                    body: JSON.stringify(payload),
                });

                if (!response.ok) {
                    const errText = await response.text();
                    console.error("API başarısız yanıt:", errText);
                    return;
                }

                const result = await response.json();
                const items = Array.isArray(result.Data) ? result.Data : [];

                const projectMap = new Map();

                items.forEach((item) => {
                    if (
                        item.OrderStatu === 200 ||
                        !item.TMSVehicleRequestDocumentNo ||
                        !item.ProjectName
                    ) return;

                    const project = normalizeProjectName(item.ProjectName);
                    const despatch = !!item.TMSDespatchDocumentNo;
                    const vehicleNo = item.TMSVehicleRequestDocumentNo;
                    const key = `${project}-${vehicleNo}`;

                    if (!projectMap.has(project)) {
                        projectMap.set(project, {
                            ProjectName: project,
                            Talep: 0,
                            Tedarik: 0,
                            Verilemeyen: 0,
                            _seenKeys: new Set(),
                        });
                    }

                    const projData = projectMap.get(project);
                    if (!projData._seenKeys.has(key)) {
                        projData._seenKeys.add(key);
                        projData.Talep += 1;
                        if (despatch) {
                            projData.Tedarik += 1;
                        } else {
                            projData.Verilemeyen += 1;
                        }
                    }
                });

                const finalData = Array.from(projectMap.values()).map((p) => {
                    delete p._seenKeys;
                    return p;
                });

                setOdakData(finalData);
            } catch (err) {
                console.error("Odak API hatası:", err);
            }
        }

        fetchOdakData();
    }, []);

    useEffect(() => {
        if (data.length > 1 || odakData.length > 0) {
            const allProjects = new Set();

            data.slice(1).forEach((row) => allProjects.add(row["PROJE ADI"]));
            odakData.forEach((item) => allProjects.add(item.ProjectName));

            const merged = Array.from(allProjects).map((projectName) => {
                const supaRow = data.slice(1).find((r) => r["PROJE ADI"] === projectName) || {};
                const odakRow = odakData.find((o) => o.ProjectName === projectName) || {};

                return {
                    ...supaRow,
                    "PROJE ADI": projectName,
                    "TALEP (Odak)": odakRow?.Talep || 0,
                    "TEDARİK (Odak)": odakRow?.Tedarik || 0,
                    "VERİLEMEYEN (Odak)": odakRow?.Verilemeyen || 0,
                };
            });

            setMergedData(merged);
        }
    }, [data, odakData]);

    const mergedColumns = [...columnOrder, "TALEP (Odak)", "TEDARİK (Odak)", "VERİLEMEYEN (Odak)"];

    return (
        <div className="app-container">
            <div className="section">
                <h2>🟣 Supabase + Odak Birleştirilmiş Tablo</h2>
                {mergedData.length > 0 ? (
                    <div className="table-wrapper">
                        <table className="styled-table">
                            <thead>
                                <tr>
                                    {mergedColumns.map((col) => (
                                        <th key={col}>{col}</th>
                                    ))}
                                </tr>
                            </thead>
                            <tbody>
                                {mergedData.map((row, idx) => (
                                    <tr key={idx}>
                                        {mergedColumns.map((col, i) => {
                                            let value = row[col];
                                            let style = {};

                                            if (col === "TED. %") {
                                                const parsed = parseFloat(value);
                                                if (!isNaN(parsed)) {
                                                    const percentage = Math.round(parsed * 100);
                                                    value = `%${percentage}`;
                                                    style = {
                                                        color:
                                                            percentage < 70
                                                                ? "#e74c3c"
                                                                : percentage < 90
                                                                    ? "#f39c12"
                                                                    : "#27ae60",
                                                        fontWeight: "bold",
                                                    };
                                                }
                                            }

                                            if (
                                                col === "HEDEF ÜSTÜ SEFER" ||
                                                col === "HEDEF ALTI SEFER" ||
                                                col === "HEDEF SEFER"
                                            ) {
                                                const parsed = parseFloat(value);
                                                if (!isNaN(parsed)) {
                                                    value = `${parsed.toLocaleString("tr-TR")} ₺`;
                                                    if (col === "HEDEF ÜSTÜ SEFER") {
                                                        style = {
                                                            color: parsed > 0 ? "#27ae60" : "#e74c3c",
                                                            fontWeight: "bold",
                                                        };
                                                    }
                                                }
                                            }

                                            if (col === "TEDARİK (Odak)") style.color = "#27ae60";
                                            if (col === "VERİLEMEYEN (Odak)") style.color = "#e74c3c";

                                            return (
                                                <td key={i} style={style}>
                                                    {value}
                                                </td>
                                            );
                                        })}
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>
                ) : (
                    <p className="loading">Veriler yükleniyor...</p>
                )}
            </div>
        </div>
    );
}

export default App;
